extension SBSDKDocumentScannerViewController {
  func withFinderCopy() {
    let config = SBSDKBaseScannerViewFinderConfiguration()
    config.isViewFinderEnabled = viewFinderConfiguration.isViewFinderEnabled
    config.lineColor = viewFinderConfiguration.lineColor
    config.lineWidth = viewFinderConfiguration.lineWidth
    config.backgroundColor = viewFinderConfiguration.backgroundColor
    config.lineCornerRadius = viewFinderConfiguration.lineCornerRadius
    config.minimumInset = viewFinderConfiguration.minimumInset
    config.aspectRatio = viewFinderConfiguration.aspectRatio
    viewFinderConfiguration = config
  }
  
  func withGeneralConfigCopy() {
    let config = SBSDKBaseScannerGeneralConfiguration()
    config.photoQualityPrioritization = generalConfiguration.photoQualityPrioritization
    config.videoContentMode = generalConfiguration.videoContentMode
    generalConfiguration = config
  }
    
  func withAutoSnapConfigCopy() {
      let config = SBSDKDocumentScannerPolygonConfiguration()
      config.enabled = autoSnapProgressPolygonConfiguration.enabled
      config.strokeWidth = autoSnapProgressPolygonConfiguration.strokeWidth
      config.strokeColor = autoSnapProgressPolygonConfiguration.strokeColor
      autoSnapProgressPolygonConfiguration = config
    }
}

extension UIColor {
    var transparentAlpha: UIColor {
        var alpha: CGFloat = 0
        getRed(nil, green: nil, blue: nil, alpha: &alpha)
        return withAlphaComponent(alpha * 0.2)
    }
}

